import { Table, Thead, Tr, Th, Tbody, Td } from '@chakra-ui/react';
import React, {useState, useEffect } from 'react';
import Axios from 'axios';

  function Application(props) {

  const [data, setData] = useState([]);

    useEffect(() => {
      Axios.get('http://localhost:3001/api/utilisateur/${props.etablissement}').then(res => {  
        setData({...res.data, etablissement: props.etablissement })
    })
    });

  const Obtenir_element_nom = () => {

      return (
       <Tr>
        <Td>{data.id}</Td>
        <Td>{data.etablissement_type}</Td>
        <Td>{data.etablissement}</Td>
        <Td>{data.location}</Td>
        <Td>{data.address}</Td>
        <Td>{data.mail}</Td>
       </Tr>
      )

     }

  return (
  <div>
   <Table>
    <Thead>
     <Tr>
      <Th>id</Th>
      <Th>etablissement_type</Th>
      <Th>etablissement</Th>
      <Th>location</Th>
      <Th>address</Th>
      <Th>mail</Th>
     </Tr>
    </Thead>

   <Tbody>{Obtenir_element_nom()}</Tbody>
  </Table>
 </div>
  );
}

export default Application;
